import { useCallback, useMemo, useRef } from 'react';
import { type ControlProps, useControl } from './use-control.ts';
import { useStableCallback } from './use-stable-callback.ts';

type Func<TArgs extends any[] = [], TRet = void> = (...val: TArgs) => TRet;
type Predicate<TArgs extends any[] = []> = Func<TArgs, boolean>;

type UseArrayControlProps<T extends readonly unknown[], TCtx = void> = ControlProps<T, TCtx>;

const emptyArray = [] as readonly unknown[];
/**
 * A hook to manage the state of a list of items.
 */
export function useArrayControl<TList extends readonly unknown[], TCtx = void>(
  props: UseArrayControlProps<TList, TCtx> = { finalValue: emptyArray as TList }
) {
  type T = TList[number];
  type FinderFn = Predicate<[item: T, index: number, list: TList | T[]]>;
  type ReplacerFn = Func<[item: T, index: number, list: TList | T[]], T>;
  type Finder = T | FinderFn;
  type Replacer = T | ReplacerFn;

  const [value, setValue] = useControl<TList, TCtx>({ ...props, finalValue: emptyArray as TList });

  const append = useStableCallback((items: T[], ctx?: TCtx) => {
    if (items.length === 0) return () => {};

    setValue(current => [...current, ...items] as unknown as TList, ctx);

    return () => {
      setValue(current => current.filter(item => !items.includes(item)) as unknown as TList, ctx);
    };
  });

  const insert = useStableCallback((element: Replacer, insertBefore?: Finder, ctx?: TCtx) => {
    const finderFn =
      typeof insertBefore === 'function'
        ? (insertBefore as FinderFn)
        : insertBefore == null
          ? null
          : (val: T) => val === insertBefore;
    const replacerFn = typeof element === 'function' ? (element as ReplacerFn) : () => element;
    return setValue(current => {
      const newList = [...current];
      const index = finderFn ? newList.findIndex(finderFn) : current.length;
      const el = replacerFn(newList[index], index, newList);
      newList.splice(index, 0, el);
      return newList as unknown as TList;
    }, ctx);
  });

  const insertAt = useStableCallback((idx: number, element: Replacer) => insert(element, (_, i) => i === idx));

  const upsert = useStableCallback((element: Replacer, replace?: Finder, ctx?: TCtx) => {
    const finderFn =
      typeof replace === 'function' ? (replace as FinderFn) : replace == null ? null : (val: T) => val === replace;

    const replacerFn = typeof element === 'function' ? (element as ReplacerFn) : () => element;

    return setValue(current => {
      const newList = [...current];
      const indices = finderFn ? newList.map((x, i, l) => (finderFn(x, i, l) ? i : null)).filter(x => x != null) : [];

      if (indices.length === 0) {
        newList.push(replacerFn(undefined as any, newList.length, newList));
      } else {
        for (const index of indices) {
          newList[index] = replacerFn(newList[index], index, newList);
        }
      }
      return newList as unknown as TList;
    }, ctx);
  });

  const modify = useStableCallback((finder: Finder, replacer: Replacer, ctx?: TCtx) => {
    const finderFn = typeof finder === 'function' ? (finder as FinderFn) : (val: T) => val === finder;
    const replacerFn = typeof replacer === 'function' ? (replacer as ReplacerFn) : () => replacer;
    return setValue(
      current =>
        current.map((item, index) =>
          finderFn(item, index, current) ? replacerFn(item, index, current) : item
        ) as unknown as TList,
      ctx
    );
  });

  const modifyAt = useStableCallback((idx: number, replacer: Replacer, ctx?: TCtx) => {
    const replacerFn = typeof replacer === 'function' ? (replacer as ReplacerFn) : () => replacer;
    return setValue(current => {
      const newList = [...current];
      newList[idx] = replacerFn(newList[idx], idx, newList);
      return newList as unknown as TList;
    }, ctx);
  });

  const remove = useStableCallback((finder: Finder, ctx?: TCtx) => {
    const finderFn = typeof finder === 'function' ? (finder as FinderFn) : (val: T) => val === finder;
    setValue(current => current.filter((item, index) => !finderFn(item, index, current)) as unknown as TList, ctx);
  });

  const removeAt = useStableCallback((idx?: number, ctx?: TCtx) =>
    remove((_, i, list) => i === (idx ?? list.length - 1), ctx)
  );

  const toggle = useStableCallback((item: T, finder?: Finder, ctx?: TCtx) => {
    const finderFn = typeof finder === 'function' ? (finder as FinderFn) : (val: T) => val === (finder ?? item);
    return setValue(current => {
      const index = (current as unknown as T[]).findIndex(finderFn);
      if (index >= 0) return current.filter((_, i) => i !== index) as unknown as TList;
      return [...current, item] as unknown as TList;
    }, ctx);
  });

  const reorder = useStableCallback((oldIndex: number, newIndex?: number, ctx?: TCtx) => {
    if (oldIndex === newIndex) return;
    return setValue(current => {
      const newList = [...current];
      const [removed] = newList.splice(oldIndex, 1);
      if (newIndex == null) newList.push(removed);
      else newList.splice(newIndex, 0, removed);
      return newList as unknown as TList;
    }, ctx);
  });

  const includes = useCallback(
    (finder: Finder) => {
      const finderFn = typeof finder === 'function' ? (finder as FinderFn) : (val: T) => val === finder;
      return (value as unknown as T[]).some(finderFn);
    },
    [value]
  );

  const prevList = useRef(value);
  const keys = useMemo(() => {
    function recreateKeys() {
      prevList.current = value;
      return value.map((_, i) => i);
    }

    // Short-circuit if the list is the same as the previous list
    if (prevList.current === value) return recreateKeys();

    // If the length of the list has changed, recalculate all keys
    if (prevList.current.length !== value.length) return recreateKeys();

    // If the new list is the reordered version of the previous list, return the previous keys in the new order
    const newKeys: number[] = [];
    for (let i = 0; i < value.length; i++) {
      const prevIndex = prevList.current.indexOf(value[i]);
      if (prevIndex < 0) return recreateKeys();
      newKeys.push(prevIndex);
    }
    return newKeys;
  }, [value]);

  return {
    value,
    setValue,

    /**
     * Returns the list of keys that can be assigned to React key property.
     * It takes reordering into account and returns the previous keys in the new order if the list is reordered.
     * This is useful if the list items don't have unique IDs, but relies on the index of the element.
     */
    keys,

    /**
     * Append items to the list. Returns a function to remove the appended items.
     *
     * @example
     * const { append } = useList();
     * useEffect(() => append(items), [append, items]);
     */
    append,

    insert,
    insertAt,
    upsert,
    modify,
    modifyAt,
    remove,
    removeAt,
    toggle,
    reorder,
    includes,
  };
}
